<section class="page-heading"><div><p class="eyebrow">Lançamento</p><h1><?=e($item['competencia'])?></h1><p><?=e($item['status'])?></p></div><?php if($canManage&&LancamentoStateMachine::editable($item['status'])):?><a href="/lancamentos/<?=e(rawurlencode($item['id']))?>/editar">Editar</a><?php endif;?></section><section class="panel"><p>Indicador: <?=e($item['indicadorId'])?></p><p>Unidade: <?=e($item['unidadeApuradora'])?></p><p>Observação: <?=e($item['observacaoArea'])?></p><?php if($canManage&&in_array(LancamentoStateMachine::normalize($item['status']),array('Rascunho','Devolvido para ajuste','Retificado'),true)):?><form method="post" action="/lancamentos/<?=e($item['id'])?>/submeter"><input type="hidden" name="_csrf_token" value="<?=e(Auth::csrfToken())?>"><button>Submeter</button></form><?php endif;?><?php if($canManage&&LancamentoStateMachine::deletable($item['status'])):?><form method="post" action="/lancamentos/<?=e($item['id'])?>/excluir"><input type="hidden" name="_csrf_token" value="<?=e(Auth::csrfToken())?>"><button>Excluir rascunho</button></form><?php endif;?><form method="post" enctype="multipart/form-data" action="/lancamentos/<?=e($item['id'])?>/evidencias"><input type="hidden" name="_csrf_token" value="<?=e(Auth::csrfToken())?>"><input type="file" name="evidencia" required><input name="descricao" placeholder="Descrição"><button>Anexar evidência</button></form></section>
